import './Section.css';

class Section extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
        expanded: true,
    }
    this.handleClick = this.handleClick.bind(this)
  }

  handleClick() {
      this.setState(state => ({
          expanded: !this.state.expanded,
      }));
      alert(this.state.expanded)
  }

